from flask import Flask, render_template, redirect, url_for, request
from datetime import datetime
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

# Helper functions to read and write data files

def read_users():
    users = []
    try:
        with open('data/users.txt', 'r') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 4:
                    users.append({
                        'username': parts[0],
                        'email': parts[1],
                        'phone': parts[2],
                        'full_name': parts[3]
                    })
    except FileNotFoundError:
        pass
    return users


def read_menu():
    menu = []
    try:
        with open('data/menu.txt', 'r') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 8:
                    try:
                        dish = {
                            'dish_id': int(parts[0]),
                            'name': parts[1],
                            'category': parts[2],
                            'price': float(parts[3]),
                            'description': parts[4],
                            'ingredients': parts[5],
                            'dietary': parts[6],
                            'avg_rating': float(parts[7])
                        }
                        menu.append(dish)
                    except ValueError:
                        continue
    except FileNotFoundError:
        pass
    return menu


def read_reservations():
    reservations = []
    try:
        with open('data/reservations.txt', 'r') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 10:
                    try:
                        reservation = {
                            'reservation_id': int(parts[0]),
                            'username': parts[1],
                            'guest_name': parts[2],
                            'phone': parts[3],
                            'email': parts[4],
                            'party_size': int(parts[5]),
                            'date': parts[6],
                            'time': parts[7],
                            'special_requests': parts[8],
                            'status': parts[9]
                        }
                        reservations.append(reservation)
                    except ValueError:
                        continue
    except FileNotFoundError:
        pass
    return reservations


def save_reservations(reservations):
    try:
        with open('data/reservations.txt', 'w') as f:
            for r in reservations:
                line = "{}|{}|{}|{}|{}|{}|{}|{}|{}|{}\n".format(
                    r['reservation_id'], r['username'], r['guest_name'], r['phone'], r['email'],
                    r['party_size'], r['date'], r['time'], r['special_requests'], r['status'])
