                <option value="{{ size }}">{{ size }}</option>
                {% endfor %}
            </select>
            <button type="submit" id="join-waitlist-button">Join Waitlist</button>
        </form>

        <div id="user-position">
            {% if user_position is not none %}
                <p>Your position in the waitlist: {{ user_position }}</p>
            {% else %}
                <p>You are not currently in the waitlist.</p>
            {% endif %}
        </div>

